const source = $json.body && typeof $json.body === 'object' ? $json.body : $json;

const asString = (value) => (value ?? '').toString();
const asBoolean = (value, fallback = true) => {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'string') return !['false', '0', 'no'].includes(value.toLowerCase().trim());
  return fallback;
};
const asArray = (value) => Array.isArray(value) ? value : [];

const input = {
  sessionId: asString(source.sessionId || source.session_id),
  userId: asString(source.userId || source.user_id),
  fileName: asString(source.fileName || source.file_name || 'manuscript.txt'),
  originalText: asString(source.originalText || source.original_text || source.text),
  serverCorrectedText: asString(source.serverCorrectedText || source.server_corrected_text || source.text),
  includeChanges: asBoolean(source.includeChanges ?? source.include_changes, true),
  styleConfigId: asString(source.styleConfigId || source.style_config_id || 'baku-media-general-style'),
  styleRules: asArray(source.styleRules || source.style_rules),
  serverChanges: asArray(source.serverChanges || source.server_changes),
  serverSuggestions: asArray(source.serverSuggestions || source.server_suggestions),
  socialFootnote: asString(source.socialFootnote || source.social_footnote),
  glossary: asArray(source.glossary),
  editorNotes: asString(source.editorNotes || source.editor_notes),
};

if (!input.originalText.trim() && !input.serverCorrectedText.trim()) {
  throw new Error('text, originalText, or serverCorrectedText is required');
}

const rulesForPrompt = input.styleRules.map((rule) => ({
  id: rule.id,
  title: rule.title,
  category: rule.category,
  mode: rule.mode,
  description: rule.description,
  examples: rule.examples,
  note: rule.note,
}));

return [{ json: { input: { ...input, styleRules: rulesForPrompt } } }];

const { input } = $json;

const styleRulesText = input.styleRules.length
  ? input.styleRules.map((rule, index) => {
      const examples = Array.isArray(rule.examples) && rule.examples.length
        ? `\n  Примеры: ${rule.examples.map((item) => `${item.before} -> ${item.after}`).join('; ')}`
        : '';
      const note = rule.note ? `\n  Примечание: ${rule.note}` : '';
      return `${index + 1}. [${rule.mode}] ${rule.title} (${rule.id})\n  ${rule.description}${examples}${note}`;
    }).join('\n\n')
  : 'Backend не передал styleRules. Используй только общую корректуру и не меняй редакционные стандарты самовольно.';

const serverChangesText = input.serverChanges.length
  ? input.serverChanges.map((item) => `- ${item.title || item.ruleId}: ${item.count || 0}`).join('\n')
  : '- нет автоматических правок от backend';

const serverSuggestionsText = input.serverSuggestions.length
  ? input.serverSuggestions.map((item) => `- ${item.title || item.ruleId}: ${item.message || ''}`).join('\n')
  : '- нет подсказок от backend';

const glossaryText = input.glossary.length
  ? JSON.stringify(input.glossary, null, 2)
  : '[]';

const outputSchema = {
  correctedText: 'финальный вычитанный текст',
  changes: [
    {
      type: 'grammar|typo|punctuation|style_rule|legal_marking|other',
      description: 'короткое описание изменения',
      before: 'фрагмент до правки, если уместно',
      after: 'фрагмент после правки, если уместно',
      ruleId: 'id правила, если применимо'
    }
  ],
  warnings: [
    {
      type: 'name_variant|yo|date|century|azerbaijani_term|ambiguous|other',
      message: 'что нужно проверить человеку',
      fragment: 'фрагмент текста, если есть'
    }
  ],
  notesForEditor: 'одно-два предложения о важных рисках или пустая строка'
};

const prompt = `Ты — серверный корректор журнала Baku Media. Работаешь после первого backend-слоя, который уже применил жесткие типографские правила.

Главная задача:
- исправить ошибки, опечатки, согласование, очевидную пунктуацию;
- привести текст к переданным редакционным правилам;
- исправлять явные орфографические ошибки в общеупотребительных словах автоматически;
- исправлять грамматические ошибки и нарушения согласования автоматически, если правильный вариант очевиден;
- доводить фразу до нормативной формы целиком, а не ограничиваться частичной заменой одного элемента;
- НЕ переписывать авторский стиль без необходимости;
- НЕ менять имена собственные, азербайджанские топонимы и реалии по догадке;
- НЕ применять правила mode=suggest к тексту, только warnings;
- спорные варианты выносить в warnings, а не исправлять самовольно;
- не удалять юридические сноски и маркировки.

Как использовать правила:
- Правила с mode=auto можно применять, если это не ломает цитату, имя собственное или смысл.
- Правила с mode=suggest НЕЛЬЗЯ применять к correctedText. Даже если suggested-вариант кажется очевидным, оставь текст как есть и добавь warning. Это жесткое ограничение.
- Backend передает правила в каждом запросе. Считай их единственным актуальным источником редакционного стандарта.
- Если в тексте есть обычная опечатка или орфографическая ошибка, например в общеупотребительном слове или форме глагола, исправляй ее в correctedText и добавляй в changes.
- Если после редакционной или типографической правки фраза остается грамматически неправильной, доведи ее до нормативной формы автоматически.
- Если ты меняешь числовое обозначение века на римское, обязательно проверь грамматику всей конструкции целиком.
- Исправляй не только запись века, но и форму слова по контексту: например, «в 19 век» -> «в XIX веке», а не «в XIX век».
- Если правильная грамматическая форма очевидна, не выноси такой случай в warnings.
- НЕ оставляй явные опечатки в correctedText ради демонстрации ошибки, примера, теста или близости к исходнику.
- НЕ пиши в warnings, что ошибка сохранена как в исходнике, оставлена для примера или требует ручной проверки, если это обычная орфографическая или грамматическая ошибка.
- В warnings выноси только спорные имена собственные, неоднозначные топонимы, сомнительные смысловые случаи и то, что действительно требует решения редактора.
- Ошибки вроде «объеденили», «прийдут», «прейдут» и другие обычные орфографические ошибки не требуют ручной проверки и должны исправляться автоматически.
- Конструкции вроде «в 14 век», «в 19 век» и аналогичные случаи после нормализации века не требуют ручной проверки, если по контексту очевидно, что нужно «в XIV веке», «в XIX веке».
- Если упоминаются Facebook или Instagram, приводи их к единому каноническому написанию: Facebook* и Instagram*.
- Не оставляй варианты вроде facebook, instagram, FACEBOOK, INSTAGRAM, если нет специальной причины сохранить регистр исходника.
- Если юридическая маркировка требуется, применяй ее сразу к канонической форме: Facebook* и Instagram*.

Как распределять результат:
- changes: орфография, пунктуация, грамматика, типографика, редакционные автоисправления;
- warnings: только неоднозначности, а не обычные ошибки.

Редакционные правила от backend (${input.styleConfigId}):
${styleRulesText}

Автоматические правки, уже сделанные backend:
${serverChangesText}

Подсказки backend для ручной проверки:
${serverSuggestionsText}

Редакционный словарь / glossary, если передан:
${glossaryText}

Дополнительные пожелания редактора:
${input.editorNotes || 'нет'}

Исходный текст до backend-правок:
${input.originalText}

Текст после backend-правок, с ним нужно работать как с основной версией:
${input.serverCorrectedText}

Верни строго валидный JSON без markdown, без code fence, без комментариев. Схема ответа:
${JSON.stringify(outputSchema, null, 2)}`;

return [{ json: { ...$json, openAiPrompt: prompt } }];

const previous = $('Build Proofreader Prompt').first().json;
const response = $input.first().json;

const extractText = (payload) => {
  if (!payload) return '';
  if (typeof payload.output_text === 'string') return payload.output_text.trim();
  if (typeof payload.text === 'string') return payload.text.trim();
  if (typeof payload.content === 'string') return payload.content.trim();
  if (typeof payload.message?.content === 'string') return payload.message.content.trim();
  if (Array.isArray(payload.output)) {
    const chunks = payload.output
      .flatMap((entry) => Array.isArray(entry.content) ? entry.content : [])
      .map((entry) => entry.text || entry.output_text || '')
      .filter(Boolean);
    if (chunks.length) return chunks.join('\n').trim();
  }
  if (Array.isArray(payload.choices)) {
    const content = payload.choices[0]?.message?.content;
    if (typeof content === 'string') return content.trim();
  }
  return '';
};

const stripFence = (text) => text
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

const safeParse = (text) => {
  const cleaned = stripFence(text);
  try {
    return JSON.parse(cleaned);
  } catch (error) {
    return {
      correctedText: cleaned || previous.input.serverCorrectedText,
      changes: [],
      warnings: [{ type: 'parse_error', message: 'OpenAI returned non-JSON output; workflow used raw text fallback.', fragment: '' }],
      notesForEditor: 'Ответ модели не удалось распарсить как JSON.'
    };
  }
};

const parsed = safeParse(extractText(response));
const correctedText = typeof parsed.correctedText === 'string' && parsed.correctedText.trim()
  ? parsed.correctedText.trim()
  : previous.input.serverCorrectedText;

const changes = Array.isArray(parsed.changes) ? parsed.changes : [];
const warnings = Array.isArray(parsed.warnings) ? parsed.warnings : [];
const notesForEditor = typeof parsed.notesForEditor === 'string' ? parsed.notesForEditor : '';

return [{
  json: {
    ok: true,
    provider: 'n8n-native-openai',
    sessionId: previous.input.sessionId,
    userId: previous.input.userId,
    fileName: previous.input.fileName,
    correctedText,
    changes,
    warnings,
    notesForEditor,
    rawModelResponse: extractText(response),
  },
}];
